module RefModule(  
    input S,  
    input R,  
    input CLK,  
    output reg Q,  
    output reg Qn  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge CLK or posedge dbg_halt) begin  
        if (S && !R) begin  
            Q <= 1;  
            Qn <= 0;  
        end  
        else if (!S && R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
        // Hold state if both S and R are low  
    end  
endmodule
